    "definition": "select `m`.`Id` AS `Id`,`m`.`UserId` AS `UserId`,`m`.`PersonCVOId` AS `PersonCVOId`,`m`.`RecordKey` AS `RecordKey`,`m`.`CreatedAt_UTC` AS `CreatedAt_UTC`,`m`.`CreatedBy` AS `CreatedBy`,`m`.`ModifiedAt_UTC` AS `ModifiedAt_UTC`,`m`.`ModifiedBy` AS `ModifiedBy`,`m`.`RecordDeleted` AS `RecordDeleted`,`h0`.`Firstname_fsx` AS `Firstname_fsx`,`h0`.`Lastname_fsx` AS `Lastname_fsx`,`h0`.`Username` AS `Username`,`h0`.`Email_fsx` AS `Email_fsx`,`h0`.`CellPhone_fsx` AS `CellPhone_fsx`,`h1e`.`Title` AS `PersonCVOTitle`,(select count(0) from `H_CVODrivers` `cc` where ((`cc`.`DriverId` = `m`.`Id`) and (`cc`.`RecordDeleted` is null))) AS `CVOsCount`,(select count(0) from `H_DistributorDrivers` `cc` where ((`cc`.`DriverId` = `m`.`Id`) and (`cc`.`RecordDeleted` is null))) AS `DistributorsCount`,(select count(0) from `H_Permits` `cc` where ((`cc`.`DriverId` = `m`.`Id`) and (`cc`.`RecordDeleted` is null))) AS `PermitsCount`,(select count(0) from `H_VehicleDrivers` `cc` where ((`cc`.`DriverId` = `m`.`Id`) and (`cc`.`RecordDeleted` is null))) AS `VehiclesCount`,(select `p`.`Code` from `H_Permits` `p` where ((`p`.`DriverId` = `m`.`Id`) and (`p`.`PermitTypeId` = 5001) and (`p`.`RecordDeleted` is null)) order by `p`.`IssuedDate_UTC` desc,`p`.`Id` desc limit 1) AS `DriverLicense`,(select `pls`.`ExpiryDate_UTC` from (`H_Permits` `p` left join `Vi_SPC_PermitLatestStatus` `pls` on((`pls`.`PermitId` = `p`.`Id`))) where ((`p`.`DriverId` = `m`.`Id`) and (`p`.`PermitTypeId` = 5001) and (`p`.`RecordDeleted` is null)) order by `p`.`IssuedDate_UTC` desc,`p`.`Id` desc limit 1) AS `DriverLicenseExpiry`,(select coalesce(`pls`.`StatusCategory`,'Unknown') from (`H_Permits` `p` left join `Vi_SPC_PermitLatestStatus` `pls` on((`pls`.`PermitId` = `p`.`Id`))) where ((`p`.`DriverId` = `m`.`Id`) and (`p`.`PermitTypeId` = 5001) and (`p`.`RecordDeleted` is null)) order by `p`.`IssuedDate_UTC` desc,`p`.`Id` desc limit 1) AS `DriverLicenseStatus`,(select count(0) from (`H_Permits` `p` join `Vi_SPC_PermitLatestStatus` `pls` on((`pls`.`PermitId` = `p`.`Id`))) where ((`p`.`DriverId` = `m`.`Id`) and (`pls`.`IsCurrentlyValid` = true) and (`p`.`RecordDeleted` is null))) AS `ValidPermitCount`,(select count(0) from (`H_Permits` `p` join `Vi_SPC_PermitLatestStatus` `pls` on((`pls`.`PermitId` = `p`.`Id`))) where ((`p`.`DriverId` = `m`.`Id`) and (`pls`.`StatusCategory` = 'Expired') and (`p`.`RecordDeleted` is null))) AS `ExpiredPermitCount`,(select count(0) from (`H_Permits` `p` join `Vi_SPC_PermitLatestStatus` `pls` on((`pls`.`PermitId` = `p`.`Id`))) where ((`p`.`DriverId` = `m`.`Id`) and (`pls`.`StatusCategory` = 'Suspended') and (`p`.`RecordDeleted` is null))) AS `SuspendedPermitCount`,(select count(0) from (`H_Permits` `p` join `Vi_SPC_PermitLatestStatus` `pls` on((`pls`.`PermitId` = `p`.`Id`))) where ((`p`.`DriverId` = `m`.`Id`) and (`pls`.`StatusCategory` = 'Revoked') and (`p`.`RecordDeleted` is null))) AS `RevokedPermitCount`,(select max(`pls`.`ExpiryDate_UTC`) from (`H_Permits` `p` join `Vi_SPC_PermitLatestStatus` `pls` on((`pls`.`PermitId` = `p`.`Id`))) where ((`p`.`DriverId` = `m`.`Id`) and (`pls`.`IsCurrentlyValid` = true) and (`p`.`RecordDeleted` is null))) AS `NextValidPermitExpiry`,(select json_arrayagg(`b`.`VehicleTypeTitle`) from (select `vt`.`Title` AS `VehicleTypeTitle` from ((`H_DriverPermitVehicleTypes` `dpvt` join `H_Permits` `p` on((`p`.`Id` = `dpvt`.`PermitId`))) join `H_ENUM_VehicleTypes` `vt` on((`vt`.`ENUM` = `dpvt`.`VehicleType`))) where ((`p`.`DriverId` = `m`.`Id`) and (`p`.`PermitTypeId` = 5001) and (`dpvt`.`RecordDeleted` is null) and (`p`.`RecordDeleted` is null)) order by `vt`.`Title`,`dpvt`.`Id` limit 3) `b`) AS `LicensedVehicleTypeBadges` from (((`H_Drivers` `m` left join `H_AAA_Synced_UserInfo` `h0` on((`h0`.`Id` = `m`.`UserId`))) left join `H_CVOs` `h1` on((`h1`.`Id` = `m`.`PersonCVOId`))) left join `H_AAA_EntityProfile` `h1e` on((`h1e`.`Id` = `h1`.`EntityId`))) where (`m`.`RecordDeleted` is null)"
